SELECT total_cases
FROM countries
WHERE country_name = 'Oman';

SELECT target_city_name, population
FROM target_cities
WHERE population > 500000;

SELECT target_country_name 
FROM target_countries 
WHERE vaccination_rate > (SELECT AVG(vaccination_rate) FROM target_countries);

SELECT COUNT(*) 
FROM target_regions 
WHERE vaccination_rate > 0.6;

SELECT SUM(total_cases) AS total_cases_sum
FROM target_cities
WHERE target_city_name = 'Salalah';

SELECT target_city_name
FROM target_cities
WHERE target_city_id = 0;

SELECT compliance_name
FROM compliance_levels
WHERE penalties = 'Fines up to $1000';
